        result.Value.where.Should().StartWith($"[{DBClientesDicInfo.PTabelaNome}].[{DBClientesDicInfo.ProBono}] = @{DBClientesDicInfo.ProBono}");
        result.Value.where.Should().NotStartWith(" AND ");
    }

